INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 0.0, "アヤネ", 401, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24001, "2020/07/31 12:00:00", 102301, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 2.21, "アヤネ", 402, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24002, "2020/07/31 12:00:00", 102301, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 0.0, "アヤネ", 403, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24003, "2020/07/31 12:00:00", 102301, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 1.99, "アサヒ", 701, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24004, "2020/07/31 12:00:00", 192201, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 2.21, "アサヒ", 702, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24005, "2020/07/31 12:00:00", 192201, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 3.33, "アサヒ", 703, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24006, "2020/07/31 12:00:00", 192201, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 0.0, "部員３", 801, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24007, "2020/07/31 12:00:00", 192301, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 2.68, "部員３", 802, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24008, "2020/07/31 12:00:00", 192301, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 0.0, "部員３", 803, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24009, "2020/07/31 12:00:00", 192301, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 0.0, "", 501, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24010, "2020/07/31 12:00:00", 192501, "やった！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 0.0, "", 502, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24011, "2020/07/31 12:00:00", 192501, "勝ったよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 0.0, "", 503, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24012, "2020/07/31 12:00:00", 192501, "いい調子！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (6, 5.33, "ミサト", 111, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24013, "2020/07/31 12:00:00", 113501, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 6.85, "ミサト", 112, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24014, "2020/07/31 12:00:00", 113501, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 3.0, "ミサト", 113, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24015, "2020/07/31 12:00:00", 113501, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 6.11, "ダイチ", 611, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24016, "2020/07/31 12:00:00", 192401, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 6.75, "ダイチ", 612, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24017, "2020/07/31 12:00:00", 192401, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 0.0, "ダイチ", 613, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24018, "2020/07/31 12:00:00", 192401, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 4.52, "ハツネ", 211, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24019, "2020/07/31 12:00:00", 113401, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 3.89, "ハツネ", 212, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24020, "2020/07/31 12:00:00", 113401, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 13.49, "ハツネ", 213, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24021, "2020/07/31 12:00:00", 113401, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 3.17, "カヤ", 311, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24022, "2020/07/31 12:00:00", 106501, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 4.42, "カヤ", 312, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 2, 24023, "2020/07/31 12:00:00", 106501, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (6, 2.89, "カヤ", 313, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24024, "2020/07/31 12:00:00", 106501, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (4, 3.71, "アヤネ", 421, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 3, 24025, "2020/07/31 12:00:00", 102301, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 5.1, "アサヒ", 721, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24026, "2020/07/31 12:00:00", 192201, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 4.34, "部員３", 821, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 3, 24027, "2020/07/31 12:00:00", 192301, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 0.0, "", 521, 10046, "2030/12/17 14:59:59", 24, 0.0, 0.0, 1, 24028, "2020/07/31 12:00:00", 192501, "いい勝負だったよ\nまたやろうね");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 5.62, "ミサト", 101, 10046, "2030/12/17 14:59:59", 24, 0.0, -360.0, 2, 24029, "2020/07/31 12:00:00", 113501, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 9.58, "ミサト", 102, 10046, "2030/12/17 14:59:59", 24, 0.0, -360.0, 2, 24030, "2020/07/31 12:00:00", 113501, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 0.0, "ミサト", 103, 10046, "2030/12/17 14:59:59", 24, 0.0, -360.0, 2, 24031, "2020/07/31 12:00:00", 113501, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2, 9.13, "ミサト", 104, 10046, "2030/12/17 14:59:59", 24, 0.0, -360.0, 1, 24032, "2020/07/31 12:00:00", 113501, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1, 8.27, "ミサト", 105, 10046, "2030/12/17 14:59:59", 24, 0.0, -360.0, 2, 24033, "2020/07/31 12:00:00", 113501, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！");
